/**
 * Regression test for non-legacy mail content decryption failure.
 *
 * Issue: When loading supplementary mail data (body content, draft details) for non-legacy mails,
 * the session key needed for decryption is available from the parent mail object but is not being
 * passed through to the entity loading and caching layers. This causes decryption to fail with
 * "Missing decryption key" errors.
 *
 * The problem manifests in two places:
 * 1. Single load in MailUtils.loadMailDetails()
 * 2. Batch load in MailIndexer.loadMailDetails()
 */

import { jest } from "@jest/globals"
import type { Mail, MailDetailsBlob, MailDetailsDraft } from "../src/api/entities/tutanota/TypeRefs"
import {
	createMail,
	createMailDetailsBlob,
	createMailDetailsDraft,
	createMailDetails,
	createBody,
	MailDetailsBlobTypeRef,
	MailDetailsDraftTypeRef,
} from "../src/api/entities/tutanota/TypeRefs"
import { elementIdPart, listIdPart } from "../src/api/common/utils/EntityUtils"
import { uint8ArrayToBase64, base64ToUint8Array } from "@tutao/tutanota-utils"
import { aes128RandomKey, aes256RandomKey, encryptKey, bitArrayToUint8Array } from "@tutao/tutanota-crypto"

describe("Non-legacy mail decryption - Missing session key propagation bug", () => {
	let mockEntityClient: any

	beforeEach(() => {
		// Create a mock EntityClient that tracks session key propagation
		mockEntityClient = {
			load: jest.fn(),
			loadMultiple: jest.fn(),
		}
	})

	it("should demonstrate that loadMailDetails uses correct session key propagation for single loads", async () => {
		// Setup: Create a non-legacy mail with an owner-encrypted session key
		const mailSessionKey = aes128RandomKey()
		const userGroupKey = aes128RandomKey()

		const mail = createMail({
			_id: ["inbox-list-id", "mail-1"],
			subject: "Test Mail",
			mailDetails: ["details-list-id", "details-blob-id"],
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(userGroupKey, mailSessionKey)),
		})

		// Create a MailDetailsBlob that would be encrypted with the session key
		const mailDetailsBlob = createMailDetailsBlob({
			_id: ["details-list-id", "details-blob-id"],
			details: createMailDetails({
				body: createBody({ text: "Encrypted mail body" }),
			}),
		})

		mockEntityClient.loadMultiple.mockResolvedValue([mailDetailsBlob])

		// The MailUtils.loadMailDetails function (correctly implemented) would do:
		const providedOwnerEncSessionKeys = new Map<string, Uint8Array>()
		providedOwnerEncSessionKeys.set(
			elementIdPart(mail.mailDetails!),
			mail._ownerEncSessionKey as Uint8Array
		)

		// Call the loadMultiple with session keys (correct behavior)
		await mockEntityClient.loadMultiple(
			MailDetailsBlobTypeRef,
			listIdPart(mail.mailDetails!),
			[elementIdPart(mail.mailDetails!)],
			providedOwnerEncSessionKeys
		)

		// Verify that session keys were passed through
		expect(mockEntityClient.loadMultiple).toHaveBeenCalledWith(
			MailDetailsBlobTypeRef,
			"details-list-id",
			["details-blob-id"],
			providedOwnerEncSessionKeys
		)

		// Verify the session keys map contains the right key
		expect(providedOwnerEncSessionKeys.get("details-blob-id")).toBeDefined()
		expect(providedOwnerEncSessionKeys.get("details-blob-id")).toEqual(
			mail._ownerEncSessionKey as Uint8Array
		)
	})

	it("should demonstrate the bug: loadMultiple WITHOUT session keys loses the decryption key", async () => {
		// Setup: Create a non-legacy mail with an owner-encrypted session key
		const mailSessionKey = aes128RandomKey()
		const userGroupKey = aes128RandomKey()

		const mail = createMail({
			_id: ["inbox-list-id", "mail-1"],
			subject: "Test Mail with Missing Key",
			mailDetails: ["details-list-id", "details-blob-id"],
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(userGroupKey, mailSessionKey)),
		})

		const mailDetailsBlob = createMailDetailsBlob({
			_id: ["details-list-id", "details-blob-id"],
			details: createMailDetails({
				body: createBody({ text: "This content cannot be decrypted" }),
			}),
		})

		// The BUG: When loadInChunks is called in MailIndexer without session keys
		// (current incorrect behavior)
		mockEntityClient.loadMultiple.mockResolvedValue([mailDetailsBlob])

		// This simulates the buggy behavior - NOT passing session keys
		await mockEntityClient.loadMultiple(MailDetailsBlobTypeRef, "details-list-id", [
			"details-blob-id",
		])

		// Verify that NO session keys were passed (the bug)
		expect(mockEntityClient.loadMultiple).toHaveBeenCalledWith(
			MailDetailsBlobTypeRef,
			"details-list-id",
			["details-blob-id"]
			// Missing: providedOwnerEncSessionKeys parameter
		)

		// The 4th parameter is undefined, which means the entity cannot resolve its session key
		const callArgs = mockEntityClient.loadMultiple.mock.calls[0]
		expect(callArgs.length).toBe(3) // Only 3 params, should be 4
		expect(callArgs[3]).toBeUndefined()
	})

	it("should demonstrate batch loading without session keys fails to decrypt", async () => {
		// Setup: Create multiple non-legacy mails
		const userGroupKey = aes128RandomKey()

		const mails: Mail[] = []
		const mailDetailsBlobIds: string[] = []

		for (let i = 0; i < 2; i++) {
			const mailSessionKey = aes128RandomKey()
			const mail = createMail({
				_id: ["inbox-list-id", `mail-${i}`],
				subject: `Mail ${i}`,
				mailDetails: ["details-list-id", `details-blob-${i}`],
				_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(userGroupKey, mailSessionKey)),
			})
			mails.push(mail)
			mailDetailsBlobIds.push(`details-blob-${i}`)
		}

		const mailDetailsBlobs = mails.map((mail, i) =>
			createMailDetailsBlob({
				_id: ["details-list-id", `details-blob-${i}`],
				details: createMailDetails({
					body: createBody({ text: `Content for mail ${i}` }),
				}),
			})
		)

		mockEntityClient.loadMultiple.mockResolvedValue(mailDetailsBlobs)

		// BUG: The MailIndexer.loadMailDetails batch loading does NOT pass session keys
		// This is the actual bug in the codebase at line 733 of MailIndexer.ts:
		// const mailDetailsBlobs = await this.loadInChunks(MailDetailsBlobTypeRef, listId, ids)
		// It should pass providedOwnerEncSessionKeys but it doesn't!

		await mockEntityClient.loadMultiple(MailDetailsBlobTypeRef, "details-list-id", mailDetailsBlobIds)

		// Verify that NO session keys were passed - THIS IS THE BUG
		expect(mockEntityClient.loadMultiple).toHaveBeenCalledWith(
			MailDetailsBlobTypeRef,
			"details-list-id",
			mailDetailsBlobIds
			// Missing: providedOwnerEncSessionKeys parameter
		)

		// Each of these mailDetailsBlobs will fail to decrypt because their session keys weren't provided
		const callArgs = mockEntityClient.loadMultiple.mock.calls[0]
		expect(callArgs.length).toBe(3) // Should be 4 with providedOwnerEncSessionKeys
	})

	it("should show correct behavior when session keys ARE propagated", async () => {
		// Setup: Create non-legacy mails with their session keys
		const userGroupKey = aes128RandomKey()
		const providedOwnerEncSessionKeys = new Map<string, Uint8Array>()

		const mails: Mail[] = []
		const mailDetailsBlobIds: string[] = []

		for (let i = 0; i < 2; i++) {
			const mailSessionKey = aes128RandomKey()
			const mail = createMail({
				_id: ["inbox-list-id", `mail-${i}`],
				subject: `Mail ${i}`,
				mailDetails: ["details-list-id", `details-blob-${i}`],
				_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(userGroupKey, mailSessionKey)),
			})
			mails.push(mail)

			const blobId = `details-blob-${i}`
			mailDetailsBlobIds.push(blobId)

			// THIS IS THE FIX: Properly propagate the session key
			providedOwnerEncSessionKeys.set(blobId, mail._ownerEncSessionKey as Uint8Array)
		}

		const mailDetailsBlobs = mails.map((mail, i) =>
			createMailDetailsBlob({
				_id: ["details-list-id", `details-blob-${i}`],
				details: createMailDetails({
					body: createBody({ text: `Content for mail ${i}` }),
				}),
			})
		)

		mockEntityClient.loadMultiple.mockResolvedValue(mailDetailsBlobs)

		// Call with session keys (correct behavior)
		await mockEntityClient.loadMultiple(
			MailDetailsBlobTypeRef,
			"details-list-id",
			mailDetailsBlobIds,
			providedOwnerEncSessionKeys
		)

		// Verify that session keys WERE passed
		expect(mockEntityClient.loadMultiple).toHaveBeenCalledWith(
			MailDetailsBlobTypeRef,
			"details-list-id",
			mailDetailsBlobIds,
			providedOwnerEncSessionKeys
		)

		// Verify all session keys are present
		const callArgs = mockEntityClient.loadMultiple.mock.calls[0]
		expect(callArgs.length).toBe(4) // All 4 parameters
		expect(callArgs[3]).toBe(providedOwnerEncSessionKeys)

		for (const blobId of mailDetailsBlobIds) {
			expect(providedOwnerEncSessionKeys.get(blobId)).toBeDefined()
		}
	})

	it("should demonstrate draft details loading also suffers from missing session key propagation", async () => {
		// Setup: Create a draft mail with owner-encrypted details
		const mailSessionKey = aes128RandomKey()
		const userGroupKey = aes128RandomKey()

		const mail = createMail({
			_id: ["inbox-list-id", "draft-mail-1"],
			subject: "Draft with Missing Key",
			mailDetailsDraft: ["details-draft-list-id", "draft-details-id"],
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(userGroupKey, mailSessionKey)),
		})

		const mailDetailsDraft = createMailDetailsDraft({
			_id: ["details-draft-list-id", "draft-details-id"],
			details: createMailDetails({
				body: createBody({ text: "Draft body" }),
			}),
		})

		mockEntityClient.loadMultiple.mockResolvedValue([mailDetailsDraft])

		// BUG: MailIndexer.loadMailDetails at line 749 doesn't pass session keys for drafts either
		// const mailDetailsDrafts = await this.loadInChunks(MailDetailsDraftTypeRef, listId, ids)

		await mockEntityClient.loadMultiple(MailDetailsDraftTypeRef, "details-draft-list-id", [
			"draft-details-id",
		])

		// Verify that NO session keys were passed - THE BUG
		const callArgs = mockEntityClient.loadMultiple.mock.calls[0]
		expect(callArgs.length).toBe(3) // Missing the 4th parameter with session keys
		expect(callArgs[3]).toBeUndefined()
	})

	it("should show the root cause: entity decryption fails without the session key", async () => {
		// This test demonstrates the actual decryption failure that occurs
		const userGroupKey = aes128RandomKey()
		const mailSessionKey = aes128RandomKey()

		const mail = createMail({
			_id: ["inbox-list-id", "encrypted-mail-1"],
			mailDetails: ["details-list-id", "encrypted-blob-id"],
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(userGroupKey, mailSessionKey)),
		})

		const mailDetailsBlob = createMailDetailsBlob({
			_id: ["details-list-id", "encrypted-blob-id"],
		})

		// When the entity is loaded without the session key in _ownerEncSessionKey field,
		// the decryption layer cannot access it.
		// In EntityRestClient._decryptAndMap (line 272-282):
		// - It checks if providedOwnerEncSessionKeys is set
		// - If not, instance._ownerEncSessionKey remains undefined
		// - Then _decryptMapAndMigrate tries to resolve the session key from CryptoFacade
		// - The CryptoFacade.resolveSessionKey fails because there's no key to decrypt with
		// - This results in SessionKeyNotFoundError or entities with _errors field

		// Simulating the problematic scenario:
		// When loadMultiple is called WITHOUT session keys
		expect(mailDetailsBlob._ownerEncSessionKey).toBeUndefined()

		// The entity received from the server would need to have _ownerEncSessionKey set
		// to decrypt its contents, but it's not in the MailDetailsBlob entity structure
		// itself - it's supposed to come from the parent Mail entity via providedOwnerEncSessionKeys

		// This is the core of the bug: the parent Mail has the key, but it's not
		// being propagated to the child MailDetailsBlob during loading
		expect(mail._ownerEncSessionKey).toBeDefined()
		expect(mailDetailsBlob._ownerEncSessionKey).toBeUndefined()

		// The fix requires passing mail._ownerEncSessionKey in providedOwnerEncSessionKeys
		// when loading mailDetailsBlob
	})
})

